import React, { useState } from 'react';
import { NavLink, Outlet, useLocation } from 'react-router-dom';
import { LayoutDashboard, Users, Package, FileText, Menu, ArrowRight } from 'lucide-react';
import { useStore } from '../context/StoreContext';

const Layout: React.FC = () => {
    const [isSidebarOpen, setIsSidebarOpen] = useState(false);
    const location = useLocation();
    const { isLoading, error } = useStore();

    return (
        <div className="flex h-screen bg-[#f3f3f4] text-[#676a6c] overflow-hidden font-sans">
            {/* Mobile Overlay */}
            {isSidebarOpen && (
                <div
                    className="fixed inset-0 bg-black/50 z-20 lg:hidden"
                    onClick={() => setIsSidebarOpen(false)}
                />
            )}

            {/* Sidebar - Solid Dark */}
            <aside
                className={`
                    fixed inset-y-0 left-0 z-30 w-[220px] flex flex-col transition-transform duration-300 ease-in-out
                    lg:relative lg:translate-x-0 bg-[#2f4050] text-[#a7b1c2]
                    ${isSidebarOpen ? 'translate-x-0' : '-translate-x-full'}
                `}
            >
                {/* Profile / Header Area - Distinctive Style */}
                <div className="p-6 bg-[#212c38] flex flex-col items-center text-center">
                    <div className="w-16 h-16 rounded-full overflow-hidden border-2 border-white/10 mb-3 grayscale-[30%]">
                        <img src="https://ui-avatars.com/api/?name=Admin+User&background=1ab394&color=fff&size=80" alt="Profile" className="w-full h-full object-cover" />
                    </div>
                    <div className="relative group cursor-pointer text-white font-semibold block w-full px-2 truncate">
                        Administrador
                    </div>
                    <div className="text-xs text-[#8095a8] mt-1">Sistema Principal</div>
                </div>

                {/* Navigation */}
                <nav className="flex-1 overflow-y-auto py-2">
                    <NavItem to="/" icon={LayoutDashboard} label="Inicio" onClick={() => setIsSidebarOpen(false)} />
                    <NavItem to="/clients" icon={Users} label="Clientes" onClick={() => setIsSidebarOpen(false)} />
                    <NavItem to="/products" icon={Package} label="Artículos" onClick={() => setIsSidebarOpen(false)} />
                    <NavItem to="/invoices" icon={FileText} label="Facturación" onClick={() => setIsSidebarOpen(false)} />
                </nav>

                <div className="p-4 bg-[#23303d] text-center">
                    {/* Generic Branding */}
                    <h1 className="text-white font-bold tracking-widest text-lg">FACTURAPRO</h1>
                    <p className="text-[10px] text-gray-500">v.1.0 Stable</p>
                </div>
            </aside>

            {/* Main Content */}
            <main className="flex-1 overflow-hidden bg-[#f3f3f4] flex flex-col h-screen w-full relative z-0">
                {/* Top Header - White & Clean */}
                <header className="bg-white border-b border-[#e7eaec] h-14 px-6 flex items-center justify-between shrink-0">
                    <div className="flex items-center gap-4">
                        <button
                            onClick={() => setIsSidebarOpen(true)}
                            className="bg-primary text-white p-1.5 rounded-sm hover:bg-primary-hover transition-colors lg:hidden"
                        >
                            <Menu size={20} />
                        </button>
                        <button className="bg-primary text-white p-1.5 rounded-sm hover:bg-primary-hover transition-colors hidden lg:block">
                            <Menu size={20} />
                        </button>
                        <h2 className="text-lg font-light hidden sm:block">Dashboard</h2>
                    </div>

                    <div className="flex items-center gap-4">
                        <button className="text-[#999c9e] hover:text-[#676a6c] text-sm font-medium flex items-center gap-2">
                            <ArrowRight size={14} /> <span>Log out</span>
                        </button>
                    </div>
                </header>

                <div className="flex-1 overflow-y-auto overflow-x-hidden p-0 w-full flex flex-col">
                    {isLoading && (
                        <div className="p-6 flex-1 flex flex-col justify-center items-center min-h-full">
                            <div className="w-8 h-8 border-4 border-primary border-t-transparent rounded-full animate-spin mb-4"></div>
                            <div className="text-text-muted font-medium animate-pulse text-sm">Sincronizando con SQL Server...</div>
                        </div>
                    )}
                    {!isLoading && error && (
                        <div className="p-6 flex-1 flex flex-col justify-center items-center min-h-full text-center">
                            <div className="bg-red-50 text-red-600 p-6 rounded-xl border border-red-100 max-w-md shadow-sm">
                                <FileText size={48} className="mx-auto mb-4 opacity-50" />
                                <div className="font-bold text-lg mb-2">Error de Conexión</div>
                                <div className="text-red-500/80 text-sm">{error}</div>
                                <p className="text-xs text-red-400 mt-4">Asegúrate de configurar `.env` e iniciar `npm run dev` en la carpeta `server/`.</p>
                            </div>
                        </div>
                    )}
                    {!isLoading && !error && (
                        <div className="p-6 w-full flex-1 flex flex-col min-h-full mx-auto animate-page-enter" key={location.pathname}>
                            <Outlet />
                        </div>
                    )}
                    <footer className="bg-white p-4 text-right text-xs text-text-muted border-t border-[#e7eaec]">
                        <strong>Copyright</strong> FacturaPro &copy; 2026
                    </footer>
                </div>
            </main>
        </div>
    );
};

// Helper Component - Flat Style
const NavItem = ({ to, icon: Icon, label, onClick }: any) => (
    <NavLink
        to={to}
        onClick={onClick}
        className={({ isActive }) =>
            `flex items-center gap-3 px-6 py-3.5 transition-all duration-200 border-l-4 group ${isActive
                ? 'bg-[#293846] text-white border-primary'
                : 'border-transparent text-[#a7b1c2] hover:bg-[#293846] hover:text-white hover:border-[#293846]'
            }`
        }
    >
        <Icon size={18} className="transition-transform duration-200 group-hover:scale-110" />
        <span className="text-[13px] font-medium transition-transform duration-200 group-hover:translate-x-1">{label}</span>
    </NavLink>
);

export default Layout;

import React, { useState, useEffect } from 'react';
import type { Client } from '../../types';

interface ClientFormProps {
    initialData?: Client | null;
    onSubmit: (data: Omit<Client, 'id' | 'createdAt'>) => void;
    onCancel: () => void;
}

const ClientForm: React.FC<ClientFormProps> = ({ initialData, onSubmit, onCancel }) => {
    const [formData, setFormData] = useState({
        name: '',
        email: '',
        phone: '',
        address: '',
        taxId: ''
    });

    useEffect(() => {
        if (initialData) {
            setFormData({
                name: initialData.name,
                email: initialData.email,
                phone: initialData.phone,
                address: initialData.address,
                taxId: initialData.taxId
            });
        }
    }, [initialData]);

    const handleChange = (e: React.ChangeEvent<HTMLInputElement>) => {
        const { name, value } = e.target;
        setFormData(prev => ({ ...prev, [name]: value }));
    };

    const handleSubmit = (e: React.FormEvent) => {
        e.preventDefault();
        onSubmit(formData);
    };

    return (
        <form onSubmit={handleSubmit} className="flex flex-col gap-4">
            <div>
                <label className="block text-sm font-medium mb-1 text-text-muted">Nombre Completo</label>
                <input
                    type="text"
                    name="name"
                    required
                    value={formData.name}
                    onChange={handleChange}
                    className="input"
                    placeholder="Juan Pérez"
                />
            </div>

            <div>
                <label className="block text-sm font-medium mb-1 text-text-muted">Identificación (RNC/Cédula)</label>
                <input
                    type="text"
                    name="taxId"
                    value={formData.taxId}
                    onChange={handleChange}
                    className="input"
                    placeholder="001-0000000-0"
                />
            </div>

            <div className="flex gap-4">
                <div className="flex-1">
                    <label className="block text-sm font-medium mb-1 text-text-muted">Email</label>
                    <input
                        type="email"
                        name="email"
                        value={formData.email}
                        onChange={handleChange}
                        className="input"
                        placeholder="juan@email.com"
                    />
                </div>
                <div className="flex-1">
                    <label className="block text-sm font-medium mb-1 text-text-muted">Teléfono</label>
                    <input
                        type="tel"
                        name="phone"
                        value={formData.phone}
                        onChange={handleChange}
                        className="input"
                        placeholder="809-555-5555"
                    />
                </div>
            </div>

            <div>
                <label className="block text-sm font-medium mb-1 text-text-muted">Dirección</label>
                <input
                    type="text"
                    name="address"
                    value={formData.address}
                    onChange={handleChange}
                    className="input"
                    placeholder="Dirección completa"
                />
            </div>

            <div className="flex justify-end gap-3 mt-6">
                <button type="button" onClick={onCancel} className="btn btn-ghost">
                    Cancelar
                </button>
                <button type="submit" className="btn btn-primary">
                    {initialData ? 'Guardar Cambios' : 'Crear Cliente'}
                </button>
            </div>
        </form>
    );
};

export default ClientForm;

import React, { useState, useEffect } from 'react';
import type { Product } from '../../types';

interface ProductFormProps {
    initialData?: Product | null;
    onSubmit: (data: Omit<Product, 'id' | 'createdAt'>) => void;
    onCancel: () => void;
}

const ProductForm: React.FC<ProductFormProps> = ({ initialData, onSubmit, onCancel }) => {
    const [formData, setFormData] = useState({
        name: '',
        description: '',
        price: 0,
        stock: 0
    });

    useEffect(() => {
        if (initialData) {
            setFormData({
                name: initialData.name,
                description: initialData.description,
                price: initialData.price,
                stock: initialData.stock
            });
        }
    }, [initialData]);

    const handleChange = (e: React.ChangeEvent<HTMLInputElement | HTMLTextAreaElement>) => {
        const { name, value } = e.target;
        setFormData(prev => ({
            ...prev,
            [name]: name === 'price' || name === 'stock' ? Number(value) : value
        }));
    };

    const handleSubmit = (e: React.FormEvent) => {
        e.preventDefault();
        onSubmit(formData);
    };

    return (
        <form onSubmit={handleSubmit} className="flex flex-col gap-4">
            <div>
                <label className="block text-sm font-medium mb-1 text-text-muted">Nombre del Producto/Servicio</label>
                <input
                    type="text"
                    name="name"
                    required
                    value={formData.name}
                    onChange={handleChange}
                    className="input"
                    placeholder="Ej: Mantenimiento Preventivo"
                />
            </div>

            <div>
                <label className="block text-sm font-medium mb-1 text-text-muted">Descripción</label>
                <textarea
                    name="description"
                    value={formData.description}
                    onChange={handleChange}
                    className="input min-h-[100px]"
                    placeholder="Detalles del producto o servicio..."
                />
            </div>

            <div className="flex gap-4">
                <div className="flex-1">
                    <label className="block text-sm font-medium mb-1 text-text-muted">Precio</label>
                    <input
                        type="number"
                        name="price"
                        min="0"
                        step="0.01"
                        required
                        value={formData.price}
                        onChange={handleChange}
                        className="input"
                    />
                </div>
                <div className="flex-1">
                    <label className="block text-sm font-medium mb-1 text-text-muted">Stock Inicial</label>
                    <input
                        type="number"
                        name="stock"
                        min="0"
                        required
                        value={formData.stock}
                        onChange={handleChange}
                        className="input"
                    />
                </div>
            </div>

            <div className="flex justify-end gap-3 mt-6">
                <button type="button" onClick={onCancel} className="btn btn-ghost">
                    Cancelar
                </button>
                <button type="submit" className="btn btn-primary">
                    {initialData ? 'Guardar Cambios' : 'Crear Producto'}
                </button>
            </div>
        </form>
    );
};

export default ProductForm;

import React, { createContext, useContext, useEffect, useState } from 'react';
import type { Client, Product, Invoice, AuditLog } from '../types';
import { v4 as uuidv4 } from 'uuid';

const API_BASE_URL = 'http://localhost:5000/api';

interface StoreState {
    clients: Client[];
    products: Product[];
    invoices: Invoice[];
    auditLogs: AuditLog[];
    isLoading: boolean;
    error: string | null;
    refreshData: () => Promise<void>;
    addClient: (client: Omit<Client, 'id' | 'createdAt'>) => Promise<void>;
    updateClient: (id: string, client: Partial<Client>) => Promise<void>;
    deleteClient: (id: string) => Promise<void>;
    addProduct: (product: Omit<Product, 'id' | 'createdAt'>) => Promise<void>;
    updateProduct: (id: string, product: Partial<Product>) => Promise<void>;
    deleteProduct: (id: string) => Promise<void>;
    addInvoice: (invoice: Omit<Invoice, 'id' | 'date'>) => Promise<void>;
}

const StoreContext = createContext<StoreState | undefined>(undefined);

export const useStore = () => {
    const context = useContext(StoreContext);
    if (!context) {
        throw new Error('useStore must be used within a StoreProvider');
    }
    return context;
};

export const StoreProvider: React.FC<{ children: React.ReactNode }> = ({ children }) => {
    const [clients, setClients] = useState<Client[]>([]);
    const [products, setProducts] = useState<Product[]>([]);
    const [invoices, setInvoices] = useState<Invoice[]>([]);
    const [auditLogs, setAuditLogs] = useState<AuditLog[]>([]);
    const [isLoading, setIsLoading] = useState(true);
    const [error, setError] = useState<string | null>(null);

    const refreshData = async () => {
        setIsLoading(true);
        setError(null);
        try {
            const [cRes, pRes, iRes, aRes] = await Promise.all([
                fetch(`${API_BASE_URL}/clients`),
                fetch(`${API_BASE_URL}/products`),
                fetch(`${API_BASE_URL}/invoices`),
                fetch(`${API_BASE_URL}/auditLogs`)
            ]);

            if (cRes.ok) setClients(await cRes.json());
            if (pRes.ok) setProducts(await pRes.json());
            if (iRes.ok) setInvoices(await iRes.json());
            if (aRes.ok) setAuditLogs(await aRes.json());
        } catch (err: any) {
            console.error('Error fetching data from API:', err);
            setError('Error conectando a la API. Asegurate de iniciar el servidor Node.js.');
        } finally {
            setIsLoading(false);
        }
    };

    useEffect(() => {
        refreshData();
    }, []);

    const addAuditLog = async (log: Omit<AuditLog, 'id' | 'timestamp'>) => {
        try {
            const newLog: AuditLog = {
                ...log,
                id: uuidv4(),
                timestamp: new Date().toISOString(),
            };
            await fetch(`${API_BASE_URL}/auditLogs`, {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify(newLog)
            });
            setAuditLogs(prev => [newLog, ...prev]);
        } catch (err) {
            console.error('Error adding audit log', err);
        }
    };

    const addClient = async (clientData: Omit<Client, 'id' | 'createdAt'>) => {
        const newClient: Client = {
            ...clientData,
            id: uuidv4(),
            createdAt: new Date().toISOString(),
        };
        try {
            const res = await fetch(`${API_BASE_URL}/clients`, {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify(newClient)
            });
            if (res.ok) {
                setClients(prev => [...prev, newClient]);
                addAuditLog({ action: 'create', entity: 'client', details: `Created client: ${newClient.name}`, user: 'Admin' });
            }
        } catch (err) {
            console.error('API Error', err);
            alert('Error creando cliente. Revisa la consola o la API.');
        }
    };

    const updateClient = async (id: string, data: Partial<Client>) => {
        try {
            const res = await fetch(`${API_BASE_URL}/clients/${id}`, {
                method: 'PUT',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify(data)
            });
            if (res.ok) {
                setClients(prev => prev.map(c => c.id === id ? { ...c, ...data } : c));
                addAuditLog({ action: 'update', entity: 'client', details: `Updated client: ${id}`, user: 'Admin' });
            }
        } catch (err) {
            console.error('API Error', err);
        }
    };

    const deleteClient = async (id: string) => {
        try {
            const res = await fetch(`${API_BASE_URL}/clients/${id}`, { method: 'DELETE' });
            if (res.ok) {
                setClients(prev => prev.filter(c => c.id !== id));
                addAuditLog({ action: 'delete', entity: 'client', details: `Deleted client: ${id}`, user: 'Admin' });
            }
        } catch (err) {
            console.error('API Error', err);
        }
    };

    const addProduct = async (productData: Omit<Product, 'id' | 'createdAt'>) => {
        let maxId = 0;
        products.forEach(p => {
            if (/^\d+$/.test(p.id)) {
                maxId = Math.max(maxId, parseInt(p.id, 10));
            }
        });
        const newId = (maxId + 1).toString();

        const newProduct: Product = {
            ...productData,
            id: newId,
            createdAt: new Date().toISOString(),
        };

        try {
            const res = await fetch(`${API_BASE_URL}/products`, {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify(newProduct)
            });
            if (res.ok) {
                setProducts(prev => [...prev, newProduct]);
                addAuditLog({ action: 'create', entity: 'product', details: `Created product: ${newProduct.name}`, user: 'Admin' });
            }
        } catch (err) {
            console.error('API Error', err);
            alert('Error creando producto. Revisa la consola o la API.');
        }
    };

    const updateProduct = async (id: string, data: Partial<Product>) => {
        try {
            const res = await fetch(`${API_BASE_URL}/products/${id}`, {
                method: 'PUT',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify(data)
            });
            if (res.ok) {
                setProducts(prev => prev.map(p => p.id === id ? { ...p, ...data } : p));
                addAuditLog({ action: 'update', entity: 'product', details: `Updated product: ${id}`, user: 'Admin' });
            }
        } catch (err) {
            console.error('API Error', err);
        }
    };

    const deleteProduct = async (id: string) => {
        try {
            const res = await fetch(`${API_BASE_URL}/products/${id}`, { method: 'DELETE' });
            if (res.ok) {
                setProducts(prev => prev.filter(p => p.id !== id));
                addAuditLog({ action: 'delete', entity: 'product', details: `Deleted product: ${id}`, user: 'Admin' });
            }
        } catch (err) {
            console.error('API Error', err);
        }
    };

    const addInvoice = async (invoiceData: Omit<Invoice, 'id' | 'date'>) => {
        const newInvoice: Invoice = {
            ...invoiceData,
            id: uuidv4(),
            date: new Date().toISOString(),
        };
        try {
            const res = await fetch(`${API_BASE_URL}/invoices`, {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify(newInvoice)
            });
            if (res.ok) {
                setInvoices(prev => [newInvoice, ...prev]);
                addAuditLog({ action: 'create', entity: 'invoice', details: `Created invoice for: ${newInvoice.clientName}`, user: 'Admin' });
                // Refresh products stock
                refreshData();
            }
        } catch (err) {
            console.error('API Error', err);
            alert('Error creando factura.');
        }
    };

    return (
        <StoreContext.Provider value={{
            clients,
            products,
            invoices,
            auditLogs,
            isLoading,
            error,
            refreshData,
            addClient,
            updateClient,
            deleteClient,
            addProduct,
            updateProduct,
            deleteProduct,
            addInvoice
        }}>
            {children}
        </StoreContext.Provider>
    );
};

import React, { useState } from 'react';
import { useStore } from '../context/StoreContext';
import { Edit2, Trash2, Plus, Search, Users } from 'lucide-react';
import type { Client } from '../types';
import Modal from '../components/ui/Modal';
import ClientForm from '../components/modules/ClientForm';

const Clients: React.FC = () => {
    const { clients, addClient, updateClient, deleteClient } = useStore();

    // View State
    const [viewClient, setViewClient] = useState<Client | null>(null);
    const [isModalOpen, setIsModalOpen] = useState(false);
    const [editingClient, setEditingClient] = useState<Client | null>(null);
    const [searchTerm, setSearchTerm] = useState('');

    const handleOpenModal = (client?: Client) => {
        setEditingClient(client || null);
        setIsModalOpen(true);
    };

    const handleCloseModal = () => {
        setEditingClient(null);
        setIsModalOpen(false);
    };

    const handleSubmit = (data: Omit<Client, 'id' | 'createdAt'>) => {
        if (editingClient) {
            updateClient(editingClient.id, data);
        } else {
            addClient(data);
        }
        handleCloseModal();
    };

    const handleDelete = (id: string) => {
        if (window.confirm('¿Está seguro de eliminar este cliente?')) {
            deleteClient(id);
        }
    };

    const filteredClients = clients.filter(client =>
        client.name.toLowerCase().includes(searchTerm.toLowerCase()) ||
        client.taxId.includes(searchTerm) ||
        client.email.toLowerCase().includes(searchTerm.toLowerCase())
    );

    // Detail Modal (Internal Component)
    const ClientDetailModal = ({ client, onClose }: any) => {
        if (!client) return null;
        return (
            <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black/60 backdrop-blur-sm animate-fade-in" onClick={onClose}>
                <div className="bg-white rounded-lg shadow-2xl w-full max-w-lg overflow-hidden animate-scale-in" onClick={e => e.stopPropagation()}>
                    <div className="bg-[#2f4050] text-white p-6 relative">
                        <button onClick={onClose} className="absolute right-4 top-4 p-1 hover:bg-white/10 rounded-full transition-colors">
                            <Trash2 className="rotate-45" size={20} />
                        </button>
                        <div className="flex items-center gap-4">
                            <div className="bg-white/10 p-3 rounded-full">
                                <Users size={32} className="text-primary" />
                            </div>
                            <div>
                                <h2 className="text-xl font-bold">{client.name}</h2>
                                <p className="text-blue-200 text-sm">{client.taxId}</p>
                            </div>
                        </div>
                    </div>

                    <div className="p-6 space-y-6">
                        <div className="grid grid-cols-2 gap-4">
                            <div className="p-4 bg-gray-50 rounded border border-gray-100">
                                <span className="block text-xs uppercase text-gray-500 font-bold mb-1">ID Cliente</span>
                                <span className="font-mono text-gray-700 select-all">{client.id}</span>
                            </div>
                            <div className="p-4 bg-gray-50 rounded border border-gray-100">
                                <span className="block text-xs uppercase text-gray-500 font-bold mb-1">Registro</span>
                                <span className="text-gray-700">{new Date(client.createdAt).toLocaleDateString()}</span>
                            </div>
                        </div>

                        <div className="space-y-4">
                            <div className="flex items-center gap-3 p-3 hover:bg-gray-50 rounded transition-colors border-b border-gray-100">
                                <span className="text-gray-400 w-6">📍</span>
                                <div>
                                    <span className="block text-xs text-gray-500">Dirección</span>
                                    <span className="text-gray-800 font-medium">{client.address}</span>
                                </div>
                            </div>
                            <div className="flex items-center gap-3 p-3 hover:bg-gray-50 rounded transition-colors border-b border-gray-100">
                                <span className="text-gray-400 w-6">📞</span>
                                <div>
                                    <span className="block text-xs text-gray-500">Teléfono</span>
                                    <span className="text-gray-800 font-medium">{client.phone}</span>
                                </div>
                            </div>
                            <div className="flex items-center gap-3 p-3 hover:bg-gray-50 rounded transition-colors border-b border-gray-100">
                                <span className="text-gray-400 w-6">✉️</span>
                                <div>
