                <div className="flex-1 p-0">
                    {clients.length === 0 ? (
                        <div className="text-center py-12">
                            <p className="text-text-muted text-lg mb-4">No hay clientes registrados aún.</p>
                            <button onClick={() => handleOpenModal()} className="btn btn-primary">
