                        <div className="table-container">
                            <table className="w-full">
                                <thead>
                                    <tr>
                                        <th className="w-24">ID</th>
                                        <th>Nombre Completo</th>
                                        <th>Identificación (Tax ID)</th>
                                        <th className="text-right">Acciones</th>
