            >
                <ClientForm
                    initialData={editingClient}
                    onSubmit={handleSubmit}
                    onCancel={handleCloseModal}
                />
            </Modal>
        </div>
    );
};

export default Clients;

import React, { useState, useMemo } from 'react';
import { useNavigate } from 'react-router-dom';
import { useStore } from '../context/StoreContext';
import { Plus, Trash2, Save, ArrowLeft } from 'lucide-react';
import type { InvoiceItem } from '../types';

const CreateInvoice: React.FC = () => {
    const navigate = useNavigate();
    const { clients, products, addInvoice } = useStore();

    const [clientId, setClientId] = useState('');
    const [selectedProductId, setSelectedProductId] = useState('');
    const [items, setItems] = useState<InvoiceItem[]>([]);
    const [notes, setNotes] = useState('');
    const [status, setStatus] = useState<'paid' | 'pending'>('pending');

    const selectedProduct = useMemo(() =>
        products.find(p => p.id === selectedProductId),
        [selectedProductId, products]);

    const handleAddItem = () => {
        if (!selectedProduct) return;

        const newItem: InvoiceItem = {
            id: crypto.randomUUID(),
            productId: selectedProduct.id,
            productName: selectedProduct.name,
            quantity: 1,
            price: selectedProduct.price,
            total: selectedProduct.price
        };

        setItems([...items, newItem]);
        setSelectedProductId('');
    };

    const updateItem = (id: string, field: keyof InvoiceItem, value: number) => {
        setItems(items.map(item => {
            if (item.id === id) {
                const updates = { [field]: value };
                if (field === 'quantity' || field === 'price') {
                    const quantity = field === 'quantity' ? value : item.quantity;
                    const price = field === 'price' ? value : item.price;
                    updates.total = quantity * price;
                }
                return { ...item, ...updates };
            }
            return item;
        }));
    };

    const removeItem = (id: string) => {
        setItems(items.filter(item => item.id !== id));
    };

    const subtotal = items.reduce((sum, item) => sum + item.total, 0);
    const tax = subtotal * 0.18; // 18% ITBIS Example
    const total = subtotal + tax;

    const handleSubmit = (e: React.FormEvent) => {
        e.preventDefault();
        if (!clientId || items.length === 0) return;

        const client = clients.find(c => c.id === clientId);
        if (!client) return;

        addInvoice({
            clientId,
            clientName: client.name,
            items,
            subtotal,
            tax,
            total,
            status,
            notes
        });

        navigate('/invoices');
    };

    return (
        <div className="w-full">
            <div className="flex items-center gap-4 mb-6">
                <button onClick={() => navigate('/invoices')} className="text-text-muted hover:text-text-main">
                    <ArrowLeft size={24} />
                </button>
                <h2 className="text-2xl font-bold">Nueva Factura</h2>
            </div>

            <form onSubmit={handleSubmit} className="flex flex-col gap-6">
                {/* Client & Metadata Card */}
                <div className="bg-white p-6 rounded-xl shadow-sm border border-border grid md:grid-cols-2 gap-6">
                    <div>
                        <label className="block text-sm font-bold text-text-heading mb-2">Cliente</label>
                        <select
                            value={clientId}
                            onChange={(e) => setClientId(e.target.value)}
                            className="input bg-gray-50 focus:bg-white"
                            required
                        >
                            <option value="">Seleccionar Cliente...</option>
                            {clients.map(client => (
                                <option key={client.id} value={client.id}>{client.name}</option>
                            ))}
                        </select>
                    </div>
                    <div>
                        <label className="block text-sm font-bold text-text-heading mb-2">Estado de Factura</label>
                        <select
                            value={status}
                            onChange={(e) => setStatus(e.target.value as any)}
                            className="input bg-gray-50 focus:bg-white"
                        >
                            <option value="pending">Pendiente de Pago</option>
                            <option value="paid">Pagada / Completada</option>
                        </select>
                    </div>
                </div>

                {/* Items Card */}
                <div className="bg-white p-6 rounded-xl shadow-sm border border-border space-y-6">
                    <div className="flex flex-col md:flex-row gap-4 items-end border-b border-border pb-6">
                        <div className="flex-1 w-full">
                            <label className="block text-sm font-bold text-text-heading mb-2">Agregar Producto o Servicio</label>
                            <select
                                value={selectedProductId}
                                onChange={(e) => setSelectedProductId(e.target.value)}
                                className="input bg-gray-50 focus:bg-white"
                            >
                                <option value="">Buscar en el inventario...</option>
                                {products.map(product => (
                                    <option key={product.id} value={product.id}>
                                        {product.name} - RD$ {product.price.toLocaleString()}
                                    </option>
                                ))}
                            </select>
                        </div>
                        <button
                            type="button"
                            onClick={handleAddItem}
                            disabled={!selectedProductId}
                            className="btn btn-primary h-[42px] px-6 whitespace-nowrap"
                        >
                            <Plus size={18} />
                            Agregar Item
                        </button>
                    </div>

                    <div className="rounded-lg border border-border overflow-hidden">
                        <table className="w-full">
                            <thead className="bg-[#f8fafc]">
                                <tr>
                                    <th className="py-3 px-4 font-bold text-text-heading">Descripción</th>
                                    <th className="w-24 py-3 px-4 text-center font-bold text-text-heading">Cant.</th>
                                    <th className="w-32 py-3 px-4 text-right font-bold text-text-heading">Precio</th>
                                    <th className="w-32 text-right py-3 px-4 font-bold text-text-heading">Total</th>
                                    <th className="w-16 py-3 px-4"></th>
                                </tr>
                            </thead>
                            <tbody className="divide-y divide-border">
                                {items.length === 0 ? (
                                    <tr>
                                        <td colSpan={5} className="text-center text-text-muted py-12 italic bg-gray-50/50">
                                            No hay items agregados a la factura. Selecciona un producto arriba.
                                        </td>
                                    </tr>
                                ) : (
                                    items.map(item => (
                                        <tr key={item.id} className="hover:bg-blue-50/30 transition-colors bg-white">
                                            <td className="py-3 px-4">{item.productName}</td>
                                            <td className="py-3 px-4">
                                                <input
                                                    type="number"
                                                    min="1"
                                                    value={item.quantity}
                                                    onChange={(e) => updateItem(item.id, 'quantity', Number(e.target.value))}
                                                    className="input py-1 px-2 text-center h-8 text-sm"
                                                />
                                            </td>
                                            <td className="py-3 px-4">
                                                <input
                                                    type="number"
                                                    min="0"
                                                    step="0.01"
                                                    value={item.price}
                                                    onChange={(e) => updateItem(item.id, 'price', Number(e.target.value))}
                                                    className="input py-1 px-2 text-right h-8 text-sm"
                                                />
                                            </td>
                                            <td className="text-right font-bold text-text-heading py-3 px-4">
                                                ${item.total.toLocaleString('es-DO', { minimumFractionDigits: 2 })}
                                            </td>
                                            <td className="text-center py-3 px-4">
                                                <button
                                                    type="button"
                                                    onClick={() => removeItem(item.id)}
                                                    className="text-gray-400 hover:text-danger p-1 rounded hover:bg-red-50 transition-all"
                                                >
                                                    <Trash2 size={16} />
                                                </button>
                                            </td>
                                        </tr>
                                    ))
                                )}
                            </tbody>
                        </table>
                    </div>
                </div>

                {/* Notes & Footer */}
                <div className="grid md:grid-cols-2 gap-6">
                    <div className="bg-white p-6 rounded-xl shadow-sm border border-border">
                        <label className="block text-sm font-bold text-text-heading mb-2">Notas Adicionales / Términos</label>
                        <textarea
                            value={notes}
                            onChange={(e) => setNotes(e.target.value)}
                            className="input h-32 resize-none bg-gray-50 focus:bg-white"
                            placeholder="Ej: Gracias por su compra. Pago requerido en 30 días..."
                        />
                    </div>

                    <div className="bg-white p-6 rounded-xl shadow-sm border border-border flex flex-col justify-center space-y-4">
                        <div className="flex justify-between text-text-muted text-sm">
                            <span>Subtotal:</span>
                            <span className="font-mono">RD$ {subtotal.toLocaleString('es-DO', { minimumFractionDigits: 2 })}</span>
                        </div>
                        <div className="flex justify-between text-text-muted text-sm">
                            <span>ITBIS (18%):</span>
                            <span className="font-mono">RD$ {tax.toLocaleString('es-DO', { minimumFractionDigits: 2 })}</span>
                        </div>
                        <div className="h-px bg-border my-2"></div>
                        <div className="flex justify-between text-2xl font-bold text-primary">
                            <span>Total:</span>
                            <span>RD$ {total.toLocaleString('es-DO', { minimumFractionDigits: 2 })}</span>
                        </div>

                        <button
                            type="submit"
                            disabled={!clientId || items.length === 0}
                            className="btn btn-primary w-full mt-2 py-4 text-base shadow-lg shadow-blue-500/20"
                        >
                            <Save size={20} />
                            Guardar y Emitir Factura
                        </button>
                    </div>
                </div>
            </form>
        </div>
    );
};

