import React from 'react';
import { useNavigate } from 'react-router-dom';
import { useStore } from '../context/StoreContext';
import { ShoppingCart, ArrowRight, CornerUpLeft, Truck, Activity, FileText } from 'lucide-react';
import { BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer } from 'recharts';

const Dashboard: React.FC = () => {
    const { invoices } = useStore();
    const navigate = useNavigate();

    // Calculations
    const totalRevenue = invoices.reduce((sum, inv) => sum + inv.total, 0);

    // Chart Data
    const clientSales = invoices.reduce((acc, inv) => {
        acc[inv.clientName] = (acc[inv.clientName] || 0) + inv.total;
        return acc;
    }, {} as Record<string, number>);

    const salesData = Object.entries(clientSales)
        .map(([name, value]) => ({ name, value }))
        .sort((a, b) => b.value - a.value)
        .slice(0, 10);

    // Recent Data
    const recentInvoices = [...invoices].sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime()).slice(0, 10);

    const StatCard = ({ type, icon: Icon, value, label, subLabel, link }: any) => {
        let iconColor = 'text-gray-400';

        // Theme Colors
        if (type === 'success') { iconColor = 'text-[#1ab394]'; }
        if (type === 'info') { iconColor = 'text-[#23c6c8]'; }
        if (type === 'warning') { iconColor = 'text-[#f8ac59]'; }
        if (type === 'danger') { iconColor = 'text-[#ed5565]'; }

        return (
            <div className="bg-white p-5 border-t-4 shadow-sm h-full flex flex-col justify-between relative hover:-translate-y-1 hover:shadow-xl transition-all duration-300 cursor-pointer group" style={{ borderColor: type === 'success' ? '#1ab394' : type === 'info' ? '#23c6c8' : type === 'warning' ? '#f8ac59' : type === 'danger' ? '#ed5565' : '#e7eaec' }}>
                <div className="flex justify-between items-start mb-2">
                    <h3 className="text-3xl font-bold text-[#676a6c] mb-1">{value}</h3>
                    <Icon size={40} className={`opacity-30 ${iconColor} absolute right-4 top-4`} />
                </div>
                <div>
                    <span className="font-bold text-sm text-[#676a6c]">{label}</span>
                    {subLabel && <div className="text-xs text-[#888888] mt-1">{subLabel}</div>}
                </div>
                {link && (
                    <div onClick={() => navigate(link)} className="mt-4 pt-2 border-t border-[#e7eaec] text-xs text-[#1ab394] cursor-pointer hover:underline flex items-center gap-1">
                        Ver detalles <ArrowRight size={10} />
                    </div>
                )}
            </div>
        );
    };

    return (
        <div className="flex flex-col space-y-6">
            {/* Header Section - Clean & Simple */}
            <div className="bg-white border-b border-[#e7eaec] p-5 mb-2 shadow-sm flex justify-between items-center -mx-6 -mt-6 lg:-mx-8 lg:-mt-8">
                <div>
                    <h2 className="text-2xl font-light text-[#676a6c]">Panel de Control</h2>
                    <ol className="flex items-center gap-2 text-sm text-[#676a6c] mt-1">
                        <li>Inicio</li>
                        <li className="text-[#a7b1c2] text-xs">/</li>
                        <li className="font-bold">Dashboard</li>
                    </ol>
                </div>
                <div className="hidden sm:block text-right">
                    <span className="bg-[#1ab394] text-white px-3 py-1 text-xs font-bold rounded-sm shadow-sm">{new Date().toLocaleDateString()}</span>
                </div>
            </div>

            {/* Top Stats Row */}
            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
                <div className="animate-fade-in-up">
                    <StatCard type="success" icon={ShoppingCart} value={`RD$ ${totalRevenue.toLocaleString()}`} label="Ingresos Totales" link="/invoices" subLabel="Facturación Acumulada" />
                </div>
                <div className="animate-fade-in-up delay-100">
                    <StatCard type="info" icon={Activity} value="0" label="Órdenes Activas" subLabel="Sin actividad reciente" />
                </div>
                <div className="animate-fade-in-up delay-200">
                    <StatCard type="warning" icon={Truck} value="12" label="Envíos Pendientes" subLabel="Requieren atención" />
                </div>
                <div className="animate-fade-in-up delay-300">
                    <StatCard type="danger" icon={CornerUpLeft} value="2" label="Devoluciones" subLabel="Pendientes de procesar" />
                </div>
            </div>

            {/* Content Row */}
            <div className="grid grid-cols-1 lg:grid-cols-3 gap-6 min-h-[400px]">
                {/* Chart Section */}
                <div className="lg:col-span-2 bg-white border border-[#e7eaec] p-0 flex flex-col h-full">
                    <div className="border-b border-[#e7eaec] px-5 py-3 flex items-center justify-between">
                        <h5 className="font-bold text-[#676a6c] uppercase text-sm">Ventas por Cliente</h5>
                        <span className="label bg-primary text-white text-[10px] px-2 py-0.5 rounded-sm">Mensual</span>
                    </div>
                    <div className="p-5 flex-1 min-h-[300px]">
                        <ResponsiveContainer width="100%" height="100%">
                            <BarChart data={salesData} margin={{ top: 20, right: 30, left: 20, bottom: 5 }}>
                                <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#e7eaec" />
                                <XAxis dataKey="name" tick={{ fontSize: 11 }} interval={0} tickLine={false} axisLine={false} />
                                <YAxis tickLine={false} axisLine={false} tick={{ fontSize: 11 }} />
                                <Tooltip cursor={{ fill: '#f8f8f8' }} contentStyle={{ border: '1px solid #e7eaec', boxShadow: 'none' }} />
                                <Bar dataKey="value" fill="#1ab394" barSize={30} />
                            </BarChart>
                        </ResponsiveContainer>
                    </div>
                </div>

                {/* Notifications / List */}
                <div className="bg-white border border-[#e7eaec] flex flex-col h-full">
                    <div className="border-b border-[#e7eaec] px-5 py-3">
                        <h5 className="font-bold text-[#676a6c] uppercase text-sm">Actividad Reciente</h5>
                    </div>
                    <div className="p-0 overflow-y-auto flex-1 bg-white">
                        <ul className="divide-y divide-[#e7eaec]">
                            {recentInvoices.map(inv => (
                                <li key={inv.id} className="p-4 hover:bg-[#fcfcfc] flex items-center gap-3">
                                    <div className="text-[#1ab394] bg-[#1ab394]/10 p-2 rounded-full">
                                        <FileText size={16} />
                                    </div>
                                    <div className="flex-1">
                                        <small className="float-right text-muted text-[10px]">{new Date(inv.date).toLocaleDateString()}</small>
                                        <strong className="block text-sm text-[#676a6c]">Factura Generada</strong>
                                        <div className="text-xs text-[#888888]">{inv.clientName} - <span className="text-[#1ab394]">RD$ {inv.total.toLocaleString()}</span></div>
                                    </div>
                                </li>
                            ))}
                            {recentInvoices.length === 0 && (
                                <li className="p-8 text-center text-muted italic text-sm">No hay actividad reciente.</li>
                            )}
                        </ul>
                    </div>
                </div>
            </div>
        </div>
    );
};

export default Dashboard;

import React, { useState } from 'react';
import { useStore } from '../context/StoreContext';
import { Edit2, Trash2, Plus, Search, Package } from 'lucide-react';
import type { Product } from '../types';
import Modal from '../components/ui/Modal';
import ProductForm from '../components/modules/ProductForm';

const Products: React.FC = () => {
    const { products, addProduct, updateProduct, deleteProduct } = useStore();

    // State for filtering and modal management
    const [searchTerm, setSearchTerm] = useState('');
    const [isModalOpen, setIsModalOpen] = useState(false);
    const [editingProduct, setEditingProduct] = useState<Product | null>(null);

    // Product Detail Modal Logic
    const [viewProduct, setViewProduct] = useState<Product | null>(null);

    const filteredProducts = products.filter(product =>
        product.name.toLowerCase().includes(searchTerm.toLowerCase()) ||
        (product.id && product.id.toLowerCase().includes(searchTerm.toLowerCase()))
    );

    const handleOpenModal = (product?: Product) => {
        if (product) {
            setEditingProduct(product);
        } else {
            setEditingProduct(null);
        }
        setIsModalOpen(true);
    };

    const handleCloseModal = () => {
        setIsModalOpen(false);
        setEditingProduct(null);
    };

    const handleSubmit = (data: Omit<Product, 'id' | 'createdAt'>) => {
        if (editingProduct) {
            updateProduct(editingProduct.id, data);
        } else {
            addProduct(data);
        }
        handleCloseModal();
    };

    const handleDelete = (id: string) => {
        if (window.confirm('¿Está seguro de eliminar este artículo?')) {
            deleteProduct(id);
        }
    };

    const ProductDetailModal = ({ product, onClose }: any) => {
        if (!product) return null;
        return (
            <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black/60 backdrop-blur-sm animate-fade-in" onClick={onClose}>
                <div className="bg-white rounded-lg shadow-2xl w-full max-w-lg overflow-hidden animate-scale-in" onClick={e => e.stopPropagation()}>
                    <div className="bg-[#2f4050] text-white p-6 relative">
                        <button onClick={onClose} className="absolute right-4 top-4 p-1 hover:bg-white/10 rounded-full transition-colors">
                            <Trash2 className="rotate-45" size={20} /> {/* Close icon simulation */}
                        </button>
                        <div className="flex items-center gap-4">
                            <div className="bg-white/10 p-3 rounded-full">
                                <Package size={32} className="text-primary" />
                            </div>
                            <div>
                                <h2 className="text-xl font-bold">{product.name}</h2>
                                <p className="text-blue-200 text-sm">{product.id ? `SKU: ${product.id}` : 'Sin ID'}</p>
                            </div>
                        </div>
                    </div>

                    <div className="p-6 space-y-6">
                        <div className="bg-gray-50 border border-gray-100 rounded-lg p-4">
                            <span className="block text-xs uppercase text-gray-500 font-bold mb-2">Descripción</span>
                            <p className="text-gray-700 leading-relaxed text-sm">{product.description}</p>
                        </div>

                        <div className="grid grid-cols-2 gap-4">
                            <div className="p-4 bg-white border border-gray-200 rounded-lg shadow-sm text-center">
                                <span className="block text-xs uppercase text-gray-500 font-bold mb-1">Precio Unitario</span>
                                <span className="font-mono text-xl font-bold text-primary">RD$ {product.price.toLocaleString('es-DO', { minimumFractionDigits: 2 })}</span>
                            </div>
                            <div className="p-4 bg-white border border-gray-200 rounded-lg shadow-sm text-center">
                                <span className="block text-xs uppercase text-gray-500 font-bold mb-1">Stock Disponible</span>
                                <span className={`font-mono text-xl font-bold ${product.stock > 10 ? 'text-emerald-600' : 'text-amber-600'}`}>
                                    {product.stock}
                                </span>
                                <span className="text-xs text-gray-400 ml-1">unidades</span>
                            </div>
                        </div>

                        <div className="bg-amber-50 border border-amber-100 p-3 rounded text-amber-800 text-xs flex gap-2 items-start">
                            <span className="text-lg">💡</span>
                            <p>El precio incluye impuestos aplicables. El stock se actualiza automáticamente con cada facturación.</p>
                        </div>

                        <div className="flex justify-end gap-3 pt-4 border-t">
                            <button onClick={() => { handleOpenModal(product); setViewProduct(null); }} className="btn btn-secondary text-xs">
                                <Edit2 size={14} /> Editar
                            </button>
                            <button onClick={onClose} className="btn btn-primary text-xs">
                                Cerrar
                            </button>
                        </div>
                    </div>
                </div>
            </div>
        );
    };

    return (
        <div>
            {viewProduct && <ProductDetailModal product={viewProduct} onClose={() => setViewProduct(null)} />}

            <div className="flex justify-between items-center mb-6">
                <div>
                    <h2 className="text-2xl font-bold">Inventario de Artículos</h2>
                    <p className="text-text-muted">Vista simplificada</p>
                </div>
                <button onClick={() => handleOpenModal()} className="btn btn-primary flex gap-2">
                    <Plus size={20} />
                    Nuevo Artículo
                </button>
            </div>

            <div className="bg-white border border-border shadow-md flex flex-col rounded-xl overflow-hidden animate-in fade-in slide-in-from-bottom-4 duration-500">
                <div className="bg-white border-b border-border px-6 py-4 flex justify-between items-center">
                    <div className="flex items-center gap-3">
                        <div className="p-2 bg-purple-50 text-purple-600 rounded-lg">
                            <Package size={20} />
                        </div>
                        <h3 className="font-bold text-lg text-text-heading">Catálogo Maestro</h3>
                    </div>
                    <div className="relative group">
                        <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-400 group-focus-within:text-purple-500 transition-colors" size={16} />
                        <input
                            type="text"
                            placeholder="Buscar artículo..."
                            className="pl-10 pr-4 py-2 text-sm rounded-lg border border-border focus:border-purple-500 focus:ring-2 focus:ring-purple-500/20 outline-none transition-all w-64 bg-gray-50 focus:bg-white"
                            value={searchTerm}
                            onChange={(e) => setSearchTerm(e.target.value)}
                        />
                    </div>
                </div>

                <div className="flex-1 p-0">
                    {products.length === 0 ? (
                        <div className="text-center py-12">
                            <Package size={48} className="mx-auto text-text-subtle mb-4 opacity-50" />
                            <p className="text-text-muted text-lg mb-4">No hay artículos registrados aún.</p>
                            <button onClick={() => handleOpenModal()} className="btn btn-primary">
                                Agregar primer artículo
                            </button>
                        </div>
                    ) : (
                        <div className="table-container">
                            <table className="w-full">
                                <thead>
                                    <tr>
                                        <th className="w-24">SKU / ID</th>
                                        <th>Nombre Artículo</th>
                                        <th className="text-right">Precio</th>
                                        <th className="text-center">Stock</th>
                                        <th className="text-right">Acciones</th>
                                    </tr>
                                </thead>
                                <tbody>
                                    {filteredProducts.map(product => (
                                        <tr key={product.id} className="hover:bg-gray-50 group transition-colors">
                                            <td>
                                                <span
                                                    onClick={() => setViewProduct(product)}
                                                    className="font-mono text-xs text-primary font-bold bg-purple-50 text-purple-600 px-2 py-1 rounded cursor-pointer hover:bg-purple-600 hover:text-white transition-colors"
                                                    title="Ver Detalles"
                                                >
                                                    {product.id}
                                                </span>
                                            </td>
                                            <td>
                                                <div className="font-medium text-text-main group-hover:text-purple-600 transition-colors">{product.name}</div>
                                                {/* Description hidden in strict compressed mode */}
                                            </td>
                                            <td className="text-right font-mono text-gray-700 font-medium">
                                                RD$ {product.price.toLocaleString('es-DO', { minimumFractionDigits: 2 })}
                                            </td>
                                            <td className="text-center">
                                                <span className={`px-2 py-0.5 rounded-full text-[10px] font-bold ${product.stock > 0 ? 'bg-success/10 text-success' : 'bg-danger/10 text-danger'}`}>
                                                    {product.stock}
                                                </span>
                                            </td>
                                            <td className="text-right">
                                                <div className="flex gap-1 justify-end">
                                                    <button
                                                        onClick={() => handleOpenModal(product)}
                                                        className="p-1.5 text-gray-500 hover:text-info hover:bg-info/10 rounded transition-all"
                                                        title="Editar"
                                                    >
                                                        <Edit2 size={16} />
                                                    </button>
                                                    <button
                                                        onClick={() => handleDelete(product.id)}
                                                        className="p-1.5 text-gray-500 hover:text-danger hover:bg-danger/10 rounded transition-all"
                                                        title="Eliminar"
                                                    >
                                                        <Trash2 size={16} />
                                                    </button>
                                                </div>
                                            </td>
                                        </tr>
                                    ))}
                                </tbody>
                            </table>
                        </div>
                    )}
                </div>
            </div>

            <Modal
                isOpen={isModalOpen}
                onClose={handleCloseModal}
                title={editingProduct ? 'Editar Artículo' : 'Nuevo Artículo'}
            >
                <ProductForm
                    initialData={editingProduct}
                    onSubmit={handleSubmit}
                    onCancel={handleCloseModal}
                />
            </Modal>
        </div>
    );
};

export default Products;

import jsPDF from 'jspdf';
import autoTable from 'jspdf-autotable';
import type { Invoice, Client } from '../types';

export const generateInvoicePDF = (invoice: Invoice, client?: Client) => {
    const doc = new jsPDF();

    // Header
    doc.setFontSize(20);
    doc.setTextColor(40, 40, 40);
    doc.text('FACTURA', 105, 15, { align: 'center' });

    doc.setFontSize(10);
    doc.text(`No. Factura: ${invoice.id.slice(0, 8)}`, 14, 25);
    doc.text(`Fecha: ${new Date(invoice.date).toLocaleDateString()}`, 14, 30);
    doc.text(`Estado: ${invoice.status.toUpperCase()}`, 14, 35);

    // Client Info
    if (client) {
        doc.text('Cliente:', 14, 45);
        doc.setFontSize(12);
        doc.text(client.name, 14, 50);
        doc.setFontSize(10);
        doc.text(`RNC/Cédula: ${client.taxId}`, 14, 55);
        doc.text(`Dirección: ${client.address}`, 14, 60);
        doc.text(`Tel: ${client.phone}`, 14, 65);
    } else {
        doc.text(`Cliente: ${invoice.clientName}`, 14, 45);
    }

    // Table
    const tableColumn = ["Producto", "Cantidad", "Precio", "Total"];
    const tableRows: (string | number)[][] = [];

    invoice.items.forEach(item => {
        const itemData = [
            item.productName,
            item.quantity,
            `$${item.price.toLocaleString('es-DO', { minimumFractionDigits: 2 })}`,
            `$${item.total.toLocaleString('es-DO', { minimumFractionDigits: 2 })}`
        ];
        tableRows.push(itemData);
    });

    autoTable(doc, {
        head: [tableColumn],
        body: tableRows,
        startY: 75,
        theme: 'grid',
        headStyles: { fillColor: [99, 102, 241] } // Primary Color
    });

    // Totals
    const finalY = (doc as any).lastAutoTable.finalY + 10;

    doc.text(`Subtotal: $${invoice.subtotal.toLocaleString('es-DO', { minimumFractionDigits: 2 })}`, 140, finalY);
    doc.text(`ITBIS (18%): $${invoice.tax.toLocaleString('es-DO', { minimumFractionDigits: 2 })}`, 140, finalY + 5);

    doc.setFontSize(12);
    doc.setFont('helvetica', 'bold');
    doc.text(`Total: $${invoice.total.toLocaleString('es-DO', { minimumFractionDigits: 2 })}`, 140, finalY + 12);

    // Footer
    if (invoice.notes) {
        doc.setFontSize(10);
        doc.setFont('helvetica', 'normal');
        doc.text('Notas:', 14, finalY + 25);
        doc.text(invoice.notes, 14, finalY + 30);
    }

    doc.save(`factura_${invoice.id.slice(0, 8)}.pdf`);
};
